+#![no_main]
+
+use libfuzzer_sys::fuzz_target;
+
+const MAX_CSV_BYTES: usize = 64 * 1024;
+
+fuzz_target!(|data: &[u8]| {
+    if data.len() > MAX_CSV_BYTES {
+        return;
+    }
+
+    let _ = fp_conformance::fuzz_csv_parse_bytes(data);
+});
